+    m_Exports.onViewerUIZoomUpdated = function (zoom) {
+        try {
+            onViewerUIUpdated();
+            adjustTrajectoryAnnotationVisibility(zoom);
+        } catch (ex) {
+            wemiException.logException(ex);
+        }
+    }
+
+    // a map to store trajectory annotations and their stations
+    // we populate this one only once, since the annotations are readonly during page lifetime
+    let m_TrajectoryAnnotations = {};
+    function adjustTrajectoryAnnotationVisibility(zoom) {
+
+
+        function reduceAnnotationVisibility(stations, visibilityFactor) {
+
+            // reduce visibility of annotations based on the visibility factor
+
+            if (isNaN(visibilityFactor)) {
+                return;
+            }
+
+            const visible = [];
+            const invisible = [];
+
+            stations.forEach((station, index) => {
+                (index % visibilityFactor === 0) ? visible.push(station) : invisible.push(station);
+            });
+            m_annotationManager.showAnnotations(visible);
+            m_annotationManager.hideAnnotations(invisible);
+        }
+
+        // Exceptions are handled by the caller
+        if (!m_annotationManager) {
+            return;
+        }
+
+        if (!m_TrajectoryAnnotations || Object.keys(m_TrajectoryAnnotations).length === 0) {
+            // get all trajectory annotations
+            const annotations = m_annotationManager.getAnnotationsList();
+            const trajectoryAnnotations = annotations.filter((a => a.isTrajectory));
+            // create a map of trajectory annotations and their stations
+            m_TrajectoryAnnotations = trajectoryAnnotations.reduce((acc, annotation) => {
+                acc[annotation.Id] = annotations.filter((a) => a.parentId === annotation.Id);
+                return acc;
+            }, {});
+
+            console.log("Trajectory annotations loaded: ", m_TrajectoryAnnotations);
+        }
+
+        if (!m_TrajectoryAnnotations || Object.keys(m_TrajectoryAnnotations).length === 0) {
+            // no need to adjust anything if there are no trajectory annotations
+            return;
+        }
+
+        console.log(zoom);
+
+        for (const key in m_TrajectoryAnnotations) {
+
+            const stations = m_TrajectoryAnnotations[key];
+            if (stations.length < 5) {
+                return; // do not adjust visibility for trajectory annotations with less than 10 stations
+            }
+
+            else if (zoom <= 0.1) {
+                m_annotationManager.hideAnnotations(stations);
+            } else if (zoom <= 0.3) {
+                reduceAnnotationVisibility(stations, 6);
+            } else if (zoom <= 0.5) {
+                reduceAnnotationVisibility(stations, 5);
+            }else if (zoom <= 1) {
+                reduceAnnotationVisibility(stations, 4);
+            } else if (zoom > 1 && zoom <= 1.5) {
+                reduceAnnotationVisibility(stations, 3);
+            } else if (zoom > 1.5 && zoom <= 2) {
+                reduceAnnotationVisibility(stations, 2);
+            } else if (zoom > 2) {
+                // show all annotations
+                m_annotationManager.showAnnotations(stations);
+            }
+        }
+
+    }
