         // Exceptions are handled automatically

@@ -2706,5 +2791,81 @@ window.DrawingAnnotationEdit = (function () {
     DrawingModule.addHandler(DrawingModule.DWGEVENT_VIEWER_CLOSED, onViewerClosed);
     DrawingModule.addHandler(DrawingModule.DWGEVENT_VIEWER_RESIZED, onViewerResized);

+
+    // create tragectory annotation object
+
+    m_Exports.createTrajectoryAnnotation = function (vertices, color, opacity) {
+
+        try {
+            // Exceptions are handled automatically
+            if (!m_annotationManager) {
+                return null; // exit if nothing to do
+            }
+            const trajectoryAnnotation = new m_webViewerInstance.Core.Annotations.PolylineAnnotation(
+                {
+                    PageNumber: 1, // drawing is always single page
+                    NoResize: true,
+                    NoDelete: true,
+                    ReadOnly: true,
+                    Style: "dash",
+                    Dashes: "2,2",
+                    StrokeThickness: 5,
+                    Color: new m_webViewerInstance.Core.Annotations.Color(255, 0, 0, 1) // default red color
+                }
+            );
+
+            trajectoryAnnotation.isTrajectory = true;
+
+            vertices.forEach((vertex, index) => {
+
+                trajectoryAnnotation.setPathPoint(index, vertex.x, vertex.y)
+
+            });
+
+            // Add and redraw the trajectory Annotation
+            m_annotationManager.addAnnotation(trajectoryAnnotation);
+            m_annotationManager.redrawAnnotation(trajectoryAnnotation);
+
+            createStationsFromTrajectoryAnnotation(trajectoryAnnotation);
+
+        }catch (ex) {
+            wemiException.logException(ex);
+        }
+    };
+
+    function createStationsFromTrajectoryAnnotation(trajectoryAnnotation) {
+
+
+        // Exceptions are handled automatically
+        if (!trajectoryAnnotation || trajectoryAnnotation.ToolName !== "AnnotationCreatePolyline") {
+            return; // exit if nothing to do
+        }
+        const radius = 10; // radius of the station circle
+        const stations = trajectoryAnnotation.getPath();
+        const stationAnnotations = [];
+        stations.forEach((station, index) => {
+            const stationAnnotation = new m_webViewerInstance.Core.Annotations.EllipseAnnotation({
+                PageNumber: trajectoryAnnotation.PageNumber,
+                NoResize: true,
+                NoDelete: true,
+                NoResize: true,
+                NoMove: true,
+                X: station.x - radius,
+                Y: station.y - radius,
+                Width: radius * 2,
+                Height: radius * 2,
+                FillColor: new m_webViewerInstance.Core.Annotations.Color(0, 0, 255, 0.66), // red color
+            });
+            stationAnnotation.parentId = trajectoryAnnotation.Id;
+
+            m_annotationManager.addAnnotation(stationAnnotation);
+            m_annotationManager.redrawAnnotation(stationAnnotation);
+
+            stationAnnotation.markAsPhotosAnnotation();
+
+            stationAnnotations.push(stationAnnotation);
+        });
+    }
+
     return m_Exports;
 }());
